     1→import React, { useEffect, useState } from "react";
     2→import { MemoryRouter, Routes, Route } from "react-router-dom";
     3→import { Box, Center, Loader, Text } from "@mantine/core";
     4→import { fetchSessions, subscribeToUpdates } from "../api";
     5→import { EmbeddedTerminal } from "../components/EmbeddedTerminal";
     6→import { SessionDetail } from "./SessionDetail";
     7→import { CheckpointDetail } from "./CheckpointDetail";
     8→import { useTabs } from "../TabsContext";
     9→
    10→interface Props {
    11→  tabId: string;
    12→  cwd: string;
    13→  command: string;
    14→  spawnedAt: number;
    15→}
    16→
    17→export function SpawnSessionScreen({ tabId, cwd, command, spawnedAt }: Props) {
    18→  const [sessionId, setSessionId] = useState<string | null>(null);
    19→  const { updateTabTitle } = useTabs();
    20→
    21→  useEffect(() => {
    22→    if (sessionId) return;
    23→
    24→    async function check() {
    25→      try {
    26→        const sessions = await fetchSessions();
    27→        const found = sessions.find((s) => new Date(s.startedAt).getTime() >= spawnedAt - 5000);
    28→        if (found) {
    29→          setSessionId(found.sessionId);
    30→          const title = found.intent ?? found.summary ?? found.prompt?.slice(0, 40) ?? found.sessionId.slice(0, 8) + "…";
    31→          updateTabTitle(tabId, title);
    32→        }
    33→      } catch { /* ignore */ }
    34→    }
    35→
    36→    // Check after 1s, then every 2s
    37→    const init = setTimeout(check, 1000);
    38→    const interval = setInterval(check, 2000);
    39→    const unsub = subscribeToUpdates(() => { check().catch(() => undefined); });
    40→
    41→    return () => {
    42→      clearTimeout(init);
    43→      clearInterval(interval);
    44→      unsub();
    45→    };
    46→  }, [sessionId, spawnedAt, tabId, updateTabTitle]);
    47→
    48→  return (
    49→    <Box style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
    50→      {/* Session detail area — fills available space above the terminal */}
    51→      <Box style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column" }}>
    52→        {sessionId ? (
    53→          <MemoryRouter
    54→            initialEntries={[{
    55→              pathname: `/sessions/${sessionId}`,
    56→              state: { hideTerminal: true },
    57→            }]}
    58→          >
    59→            <Routes>
    60→              <Route path="/sessions/:sessionId" element={<SessionDetail />} />
    61→              <Route path="/checkpoints/:checkpointId" element={<CheckpointDetail />} />
    62→            </Routes>
    63→          </MemoryRouter>
    64→        ) : (
    65→          <Center style={{ flex: 1 }}>
    66→            <Box ta="center">
    67→              <Loader size="sm" color="indigo" mb={8} />
    68→              <Text size="sm" c="dimmed">Starting session…</Text>
    69→            </Box>
    70→          </Center>
    71→        )}
    72→      </Box>
    73→
    74→      {/* Terminal — always mounted so the claude process keeps running */}
    75→      <EmbeddedTerminal cwd={cwd} command={command} />
    76→    </Box>
    77→  );
    78→}
    79→

